using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator, which is correct because
        // we explicitly configured HasDiscriminator<string>("Discriminator") to match existing documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports sync I/O (ToList, SaveChanges, etc.).
        // All queries must use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

